// src/Login.js
import React, { useState } from 'react';
import axios from 'axios';

function Login({ onLogin }) {
  const [usuario, setUsuario] = useState('');
  const [senha, setSenha] = useState('');
  const [mensagem, setMensagem] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post('/api/login', { usuario, senha });
      onLogin(res.data);
    } catch {
      setMensagem('Usuário ou senha inválidos!');
    }
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row">
      {/* Coluna da esquerda: apenas em desktop, background via public/login-side.jpg */}
      <div
        className="hidden md:block md:w-1/2 bg-cover bg-center rounded-l-2xl"
        style={{ backgroundImage: "url('/login-side.jpg')" }}
      />

      {/* Coluna do formulário */}
      <div className="flex w-full md:w-1/2 items-center justify-center bg-gray-100 p-6">
        <form
          onSubmit={handleSubmit}
          className="w-full max-w-md bg-white rounded-2xl shadow-lg p-8 space-y-6"
        >
          <h2 className="text-2xl font-bold text-gray-800 text-center">Login</h2>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Usuário
            </label>
            <input
              type="text"
              value={usuario}
              onChange={e => setUsuario(e.target.value)}
              required
              className="w-full border rounded px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-400"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Senha
            </label>
            <input
              type="password"
              value={senha}
              onChange={e => setSenha(e.target.value)}
              required
              className="w-full border rounded px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-400"
            />
          </div>

          <button
            type="submit"
            className="w-full bg-[#3172C0] hover:bg-[#255a9c] text-white py-2 rounded-full font-semibold transition"
          >
            Entrar
          </button>

          {mensagem && (
            <p className="text-red-600 text-center">{mensagem}</p>
          )}
        </form>
      </div>
    </div>
  );
}

export default Login;
